const webhook = $input.first().json;
const instanceName = webhook.instance||webhook.body?.instance||webhook.instanceName||webhook.body?.instanceName||webhook.data?.instance||webhook.instanceId||'';
const fromMe = webhook.fromMe||webhook.key?.fromMe||webhook.data?.key?.fromMe||webhook.body?.data?.key?.fromMe||false;
if (fromMe===true) return [];
const remoteJid = webhook.sender||webhook.remoteJid||webhook.key?.remoteJid||webhook.data?.key?.remoteJid||webhook.body?.data?.key?.remoteJid||'';
if (remoteJid.includes('@g.us')) return [];
const tipoMensagem = webhook.messageType||webhook.data?.messageType||webhook.body?.data?.messageType||'conversation';
const TIPOS_IGNORADOS=['senderKeyDistributionMessage','protocolMessage','reactionMessage','pollUpdateMessage'];
if (TIPOS_IGNORADOS.includes(tipoMensagem)) return [];
const numero = remoteJid.replace('@s.whatsapp.net','');
const mensagem = webhook.conversation||webhook.text||webhook.body||webhook.data?.message?.conversation||webhook.data?.message?.extendedTextMessage?.text||webhook.body?.data?.message?.conversation||'';
const nomeContato = webhook.pushName||webhook.senderName||webhook.data?.pushName||webhook.body?.data?.pushName||'Lead';
const temArquivo = ['imageMessage','documentMessage','audioMessage','videoMessage','stickerMessage'].includes(tipoMensagem);
const ehAudio = tipoMensagem==='audioMessage';
let audioBase64=webhook.mediaBase64||null,audioUrl=webhook.mediaUrl||null,audioMimetype=webhook.mimetype||'audio/ogg',audioDuration=webhook.duration||0;
let ehImagem=tipoMensagem==='imageMessage',imagemUrl=webhook.mediaUrl||null,imagemBase64=webhook.mediaBase64||null,imagemMimetype=webhook.mimetype||'image/jpeg',imagemCaption=webhook.caption||'';
let ehDocumento=['documentMessage','documentWithCaptionMessage'].includes(tipoMensagem),docUrl=webhook.mediaUrl||null,docBase64=webhook.mediaBase64||null,docMimetype=webhook.mimetype||'application/octet-stream',docFileName=webhook.fileName||webhook.filename||'documento';
if (!mensagem && !temArquivo) return [];
return [{json:{numero,mensagem,nomeContato,tipoMensagem,temArquivo,ehAudio,audioBase64,audioUrl,audioMimetype,audioDuration,ehImagem,imagemUrl,imagemBase64,imagemMimetype,imagemCaption,ehDocumento,docUrl,docBase64,docMimetype,docFileName,mensagemOriginalAudio:ehAudio,instanceName,timestamp:new Date().toISOString()}}];

const dados = $input.first().json;
let audioBase64 = dados.audioBase64;
if (!audioBase64 && dados.audioUrl) {
  try {
    const response = await fetch(dados.audioUrl);
    const arrayBuffer = await response.arrayBuffer();
    const uint8 = new Uint8Array(arrayBuffer);
    let binary = ''; uint8.forEach(b => binary += String.fromCharCode(b));
    audioBase64 = btoa(binary);
  } catch(e) { return [{ json: { ...dados, mensagem: '[Audio nao pode ser baixado]', ehAudio: false } }]; }
}
if (!audioBase64) return [{ json: { ...dados, mensagem: '[Audio sem conteudo]', ehAudio: false } }];
return [{ json: { ...dados, audioBase64 } }];

const dados = $input.first().json;
if (!dados.audioBase64) return [{ json: { ...dados, mensagem: '[Audio sem conteudo]' } }];
const response = await $helpers.request({
  method: 'POST',
  url: `https://vyvdrbkcrvklcaombjqu.supabase.co/functions/v1/llm-proxy?action=whisper&user_id=${dados.instanceName}`,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ audio_base64: dados.audioBase64, filename: 'audio.ogg', language: 'pt' }),
  responseType: 'json'
});
return [{ json: { ...dados, mensagem: response.text || '[Transcricao indisponivel]' } }];

const orig = $('Normaliza e filtra mensagem').first().json;
const transcricao = $input.first().json.mensagem || '[Transcricao indisponivel]';
return [{ json: { ...orig, ...$input.first().json, mensagem: transcricao, mensagemOriginalAudio: true } }];

const dados = $input.first().json;
const imageContent = dados.imagemBase64
  ? { type:'image_url', image_url:{ url:`data:${dados.imagemMimetype};base64,${dados.imagemBase64}`, detail:'high' } }
  : dados.imagemUrl ? { type:'image_url', image_url:{ url:dados.imagemUrl, detail:'high' } } : null;
if (!imageContent) {
  const desc = dados.imagemCaption ? `Lead enviou imagem: "${dados.imagemCaption}"` : 'Lead enviou uma imagem';
  return [{ json: { ...dados, mensagem: desc } }];
}
const response = await $helpers.request({
  method:'POST',
  url:`https://vyvdrbkcrvklcaombjqu.supabase.co/functions/v1/llm-proxy?provider=openai&user_id=${dados.instanceName}&model=gpt-4o`,
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify({ messages:[{ role:'user', content:[
    { type:'text', text: dados.imagemCaption ? `Imagem com legenda: "${dados.imagemCaption}". Descreva e analise.` : 'Descreva e analise esta imagem.' },
    imageContent
  ]}], system:'Voce descreve imagens enviadas por clientes. Seja objetivo e mencione documentos, contratos, comprovantes ou materiais relevantes.' }),
  responseType:'json'
});
const descricao = response.content || 'Imagem recebida mas nao foi possivel analisar.';
return [{ json: { ...dados, mensagem: `📷 [Imagem]:
${descricao}`, ehImagem:true } }];

const dados = $input.first().json;
const isPdf = dados.docMimetype?.includes('pdf');
if (!dados.docBase64 && !dados.docUrl) {
  return [{ json: { ...dados, mensagem: `📄 [Arquivo "${dados.docFileName}" recebido — sem conteudo legivel. Peca ao lead que descreva.]`, ehDocumento:true } }];
}
if (isPdf && dados.docBase64) {
  const response = await $helpers.request({
    method:'POST',
    url:`https://vyvdrbkcrvklcaombjqu.supabase.co/functions/v1/llm-proxy?provider=openai&user_id=${dados.instanceName}&model=gpt-4o`,
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({ messages:[{ role:'user', content:[
      { type:'text', text:`Cliente enviou "${dados.docFileName}". Extraia e resuma o conteudo principal.` },
      { type:'file', file:{ filename:dados.docFileName, file_data:`data:${dados.docMimetype};base64,${dados.docBase64}` } }
    ]}], system:'Extraia e resuma documentos enviados por clientes. Inclua datas, nomes, valores relevantes.' }),
    responseType:'json'
  });
  const texto = response.content || 'Nao foi possivel extrair.';
  return [{ json: { ...dados, mensagem: `📄 [Arquivo "${dados.docFileName}"]:
${texto}`, ehDocumento:true } }];
}
return [{ json: { ...dados, mensagem: `📄 [Arquivo "${dados.docFileName}" (${dados.docMimetype})] — Solicite o conteudo em texto.`, ehDocumento:true } }];

// Monta system prompt COMPLETO a partir do agente_config (configurado no software)
// Prompt NUNCA hardcoded — sempre do software via agente_config
const configRaw = $('Busca todas configs (agente_config)').first().json || [];
const configMap = {};
(Array.isArray(configRaw) ? configRaw : []).forEach(row => { if (row && row.chave) configMap[row.chave] = row.valor; });

const clienteRaw = $('Resolve cliente pelo instanceName').first().json;
const cliente = Array.isArray(clienteRaw) ? clienteRaw[0] : clienteRaw;
const userId = cliente && cliente.id;
const evoInstance = cliente && cliente.evo_instance;
const dadosMsg = $('Prepara contexto final').first().json;
const numero = dadosMsg.numero;
const nomeContato = dadosMsg.nomeContato || 'Lead';
const mensagem = dadosMsg.mensagem;
const mensagemOriginalAudio = dadosMsg.mensagemOriginalAudio === true;
const responderEmAudio = configMap.responder_em_audio === 'true';
const aiProvider = configMap.ai_provider || 'openai';
const aiModel = configMap.ai_model || 'gpt-4o';
const webSearchEnabled = configMap.web_search_enabled !== 'false'; // default true

// Base de conhecimento: chunks encontrados
let knowledgeSection = '';
try {
  const kbRaw = $('Busca base de conhecimento').first().json || [];
  const chunks = Array.isArray(kbRaw) ? kbRaw : [];
  if (chunks.length > 0) {
    const textos = chunks.map(c => `[${c.nome || 'Doc'}]\n${c.conteudo}`).join('\n---\n');
    knowledgeSection = '\n\nBASE DE CONHECIMENTO (use estas informações para responder com precisão):\n' + textos;
  }
} catch(e) {}

// Web URLs configuradas
let webUrlsSection = '';
try {
  const urlsRaw = configMap.web_urls_fixas || '[]';
  const urls = JSON.parse(urlsRaw);
  if (Array.isArray(urls) && urls.length > 0) {
    const lista = urls.map(u => '- ' + u.url + (u.desc ? ' (' + u.desc + ')' : '')).join('\n');
    webUrlsSection = '\n\nSITES DE REFERÊNCIA PRIORITÁRIOS (consulte antes de outras fontes):\n' + lista;
  }
} catch(e) {}

const partes = [
  configMap.sistema_prompt || 'Voce e um assistente de vendas SDR profissional. Qualifique o cliente de forma consultiva e persuasiva.',
  '',
  configMap.objetivo ? ('OBJETIVO: ' + configMap.objetivo) : '',
  configMap.tonalidade ? ('TONALIDADE: ' + configMap.tonalidade) : '',
  configMap.instrucoes_comunicacao ? ('INSTRUCOES DE COMUNICACAO:\n' + configMap.instrucoes_comunicacao) : '',
  configMap.criterios_qualificacao ? ('CRITERIOS DE QUALIFICACAO (cliente deve atender ao menos 3):\n' + configMap.criterios_qualificacao) : '',
  webUrlsSection,
  knowledgeSection,
  '',
  'QUANDO O LEAD FOR QUALIFICADO:',
  ('- Responda com: ' + (configMap.msg_qualificado || 'Perfeito! Vou encaminhar suas informacoes para nosso time especializado.')),
  '- Inclua no FINAL da mensagem exatamente este bloco JSON:',
  '```json',
  '{"qualificado":true,"nome":"Nome completo","celular":"DDD+numero","tese":"Produto/servico de interesse","resumo":"Resumo completo da conversa"}',
  '```',
  '',
  'QUANDO O LEAD NAO FOR QUALIFICADO:',
  ('- Responda com: ' + (configMap.msg_desqualificado || 'Agradecemos o contato! Se mudar de ideia, estaremos aqui.')),
  '- Inclua no FINAL:',
  '```json',
  '{"qualificado":false,"motivo":"Motivo da desqualificacao"}',
  '```',
  '',
  'REGRAS:',
  '- Faca UMA pergunta por vez',
  '- Nunca prometa resultado ou vitoria',
  '- Seja conciso e persuasivo',
  '- Deixe o cliente falar',
  !webSearchEnabled ? 'ATENCAO: NAO use busca na web. Consulte apenas a Base de Conhecimento interna.' : ''
].filter(Boolean);

return [{ json: {
  ...dadosMsg,
  userId, evoInstance, numero, nomeContato, mensagem,
  mensagemOriginalAudio, responderEmAudio, aiProvider, aiModel,
  webSearchEnabled,
  systemPrompt: partes.join('\n'),
  configMap
} }];

const historico = $('Busca historico da conversa').first().json || [];
const arr = Array.isArray(historico) ? historico : [];
const ultimaMsgAgente = [...arr].reverse().find(m => m.sender === 'agent');
const agora = new Date();
const tempoMs = ultimaMsgAgente ? agora - new Date(ultimaMsgAgente.criado_em) : Infinity;
const tempoSeg = isFinite(tempoMs) ? Math.floor(tempoMs / 1000) : 999;
return [{ json: { tempoDecorridoSeg: tempoSeg, deveEsperarSilencio: tempoSeg < 10, tempoRestanteSeg: Math.max(0, 10 - tempoSeg) } }];

const resposta = $('Chama LLM via llm-proxy').first().json.content || '';
const mensagemCliente = $('Monta system prompt').first().json.mensagem || '';
const conversaCompleta = mensagemCliente + ' ' + resposta;
const OBJECOES = {
  preco: ['caro','preco','valor','investimento','custo','pagar','muito dinheiro'],
  tempo: ['nao tenho tempo','depois','mais tarde','agora nao','ocupado','sem tempo'],
  confianca: ['nao confio','duvida','suspeito','receio','nao sei se funciona','golpe'],
  necessidade: ['nao preciso','nao tenho necessidade','ja tenho','duvido que funciona'],
  concorrencia: ['outra empresa','ja tenho fornecedor','minha solucao atual']
};
let tipoObjecao = null;
for (const [tipo,palavras] of Object.entries(OBJECOES)) {
  for (const palavra of palavras) { if (conversaCompleta.toLowerCase().includes(palavra)) { tipoObjecao=tipo; break; } }
  if (tipoObjecao) break;
}
return [{ json: { temObjecao: !!tipoObjecao, tipoObjecao: tipoObjecao||'nenhuma', conversaCompleta } }];

const ctx = $('Monta system prompt').first().json;
const texto = $('Chama LLM via llm-proxy').first().json.content || '';
const response = await $helpers.request({ method: 'POST', url: `https://vyvdrbkcrvklcaombjqu.supabase.co/functions/v1/llm-proxy?action=tts&user_id=${ctx.userId}`, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ text: texto, voice: 'nova', model: 'tts-1' }), responseType: 'json' });
return [{ json: { ...ctx, textoResposta: texto, audio_base64: response.audio_base64 || '' } }];

const dados = $input.first().json;
if (!dados.audio_base64) return [{ json: { ...dados, enviarComoAudio: false } }];
return [{ json: { ...dados, audioResposta: `data:audio/mp3;base64,${dados.audio_base64}`, enviarComoAudio: true } }];

const respostaLLM = $('Chama LLM via llm-proxy').first().json.content || '';
const ctx = $('Monta system prompt').first().json;
const match = respostaLLM.match(/```json\s*([\s\S]*?)\s*```/);
if (match) { try { const dados = JSON.parse(match[1]); return [{ json: { qualificado: dados.qualificado===true, dadosQualificacao: dados, userId: ctx.userId, numero: ctx.numero, nomeContato: ctx.nomeContato, evoInstance: ctx.evoInstance } }]; } catch(e) {} }
return [{ json: { qualificado: false, dadosQualificacao: null, userId: ctx.userId, numero: ctx.numero, nomeContato: ctx.nomeContato, evoInstance: ctx.evoInstance } }];

const configRel = $('Busca config: destino relatorio').first().json || [];
const cmap = {}; (Array.isArray(configRel)?configRel:[]).forEach(c=>{ cmap[c.chave]=c.valor; });
const dadosQ = $('Analisa qualificacao do lead').first().json;
const ctx = $('Monta system prompt').first().json;
const llmContent = $('Chama LLM via llm-proxy').first().json.content || '';
const nome = (dadosQ.dadosQualificacao && dadosQ.dadosQualificacao.nome) || ctx.nomeContato || 'Lead';
const celular = (dadosQ.dadosQualificacao && dadosQ.dadosQualificacao.celular) || ctx.numero;
const tese = (dadosQ.dadosQualificacao && dadosQ.dadosQualificacao.tese) || 'Nao especificado';
const resumo = (dadosQ.dadosQualificacao && (dadosQ.dadosQualificacao.resumo || dadosQ.dadosQualificacao.motivo)) || llmContent.substring(0,300);
const relatorio = `📊 RELATORIO DE QUALIFICACAO\n\n👤 Nome: ${nome}\n📱 Numero: ${celular}\n🎯 Interesse: ${tese}\n\n📋 Resumo:\n${resumo}\n\n⏰ ${new Date().toLocaleString('pt-BR')}`;
const numeroDestino = cmap.numero_destino || '';
const grupoDestino = cmap.grupo_destino || '';
return [{ json: { relatorio, numeroDestino, grupoDestino, enviarParaNumero: !!numeroDestino, enviarParaGrupo: !!grupoDestino, evoInstance: ctx.evoInstance } }];

const msg = $('Normaliza e filtra mensagem').first().json.mensagem || '';
const ctx = $('Busca todas configs (agente_config)').first().json;
const msgLower = msg.toLowerCase();
const KEYWORDS_TRANSFER = [
  'quero falar com', 'falar com humano', 'falar com pessoa', 'quero atendente',
  'preciso de um atendente', 'atendente humano', 'falar com alguem', 'falar com alguém',
  'quero uma pessoa', 'me passa para', 'me conecta com', 'suporte humano',
  'nao quero falar com robo', 'não quero falar com robô', 'me transfere', 'transferir'
];
const querTransferir = KEYWORDS_TRANSFER.some(kw => msgLower.includes(kw));
return [{ json: { querTransferir, mensagem: msg } }];

const clienteRaw = $('Resolve cliente pelo instanceName').first().json;
const cliente = Array.isArray(clienteRaw) ? clienteRaw[0] : clienteRaw;
const configRaw = $('Busca todas configs (agente_config)').first().json || [];
const configMap = {};
(Array.isArray(configRaw) ? configRaw : []).forEach(r => { if (r && r.chave) configMap[r.chave] = r.valor; });
const numeroAtendente = configMap.numero_atendente || configMap.numero_destino || '';
const dadosMsg = $('Normaliza e filtra mensagem').first().json;
return [{ json: { evoInstance: cliente.evo_instance, numeroAtendente, dadosMsg, configMap } }];
